sql:
SELECT COUNT(user_id) 
FROM users
WHERE role = 'admin' AND department = 'IT' AND status = 'active';

SELECT AVG(rating_score) as avg_rating
FROM session_ratings
WHERE session_id = 0;

SELECT email_address
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM training_sessions
);

SELECT u.email_address, u.last_login
FROM users u
JOIN training_sessions ts ON u.user_id = ts.user_id;
